import{_ as o,o as t,c as l,a3 as a}from"./chunks/framework.BTFg6ESq.js";const u=JSON.parse('{"title":"知识库处理器 (Knowledge Processor)","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/context-pipeline/knowledge-processor.md","filePath":"user-guide/tools/llm-chat/context-pipeline/knowledge-processor.md","lastUpdated":1779081334000}'),r={name:"user-guide/tools/llm-chat/context-pipeline/knowledge-processor.md"};function n(i,e,s,d,c,g){return t(),l("div",null,[...e[0]||(e[0]=[a('<div><h1 id="知识库处理器-knowledge-processor" tabindex="-1">知识库处理器 (Knowledge Processor) <a class="header-anchor" href="#知识库处理器-knowledge-processor" aria-label="Permalink to &quot;知识库处理器 (Knowledge Processor)&quot;">​</a></h1><p>知识库处理器负责实现 RAG (Retrieval-Augmented Generation，检索增强生成)。它能够根据当前对话内容，从关联的知识库中检索相关片段并注入到上下文。</p><h2 id="_1-工作原理" tabindex="-1">1. 工作原理 <a class="header-anchor" href="#_1-工作原理" aria-label="Permalink to &quot;1. 工作原理&quot;">​</a></h2><ol><li><strong>构建查询</strong>: 处理器取最近 N 轮对话，分别提取用户消息和 AI 回复，通过向量空间加权融合构建检索向量。</li><li><strong>检索</strong>: 调用<a href="./../../knowledge-base">知识库管理系统</a>进行检索。</li><li><strong>召回与过滤</strong>: 根据 Agent 的配置（召回数量、最低分数、字数上限）获取最相关的知识片段。</li><li><strong>格式化注入</strong>: 将片段按预设模板组装，并注入到上下文的指定位置。</li></ol><h2 id="_2-agent-级配置" tabindex="-1">2. Agent 级配置 <a class="header-anchor" href="#_2-agent-级配置" aria-label="Permalink to &quot;2. Agent 级配置&quot;">​</a></h2><p>你可以在 Agent 编辑器的 <strong>「角色设定 -&gt; 知识库 (RAG)」</strong> 面板中为每个 Agent 定制检索策略：</p><ul><li><strong>检索引擎</strong>: <ul><li><code>vector</code>: 语义检索，适合模糊匹配。</li><li><code>fulltext</code>: 关键词检索，适合精确匹配。</li><li><code>hybrid</code>: 混合模式。</li></ul></li><li><strong>Embedding 模型</strong>: 统一使用知识库全局配置的 Embedding 模型（在知识库工具的设置中配置）。</li><li><strong>结果模板</strong>: <ul><li>示例: <code>[来自知识库 &quot;{{kbName}}&quot;]:\\n{{content}}</code></li><li>支持变量: <code>{count}</code>, <code>{kbName}</code>, <code>{key}</code>, <code>{content}</code>, <code>{score}</code>, <code>{tags}</code>。</li></ul></li></ul><h2 id="_3-高级检索优化" tabindex="-1">3. 高级检索优化 <a class="header-anchor" href="#_3-高级检索优化" aria-label="Permalink to &quot;3. 高级检索优化&quot;">​</a></h2><ul><li><strong>标签门控 (Tag Gating)</strong>: 只有当最近的消息中出现了特定标签（关键词）时，才触发对特定知识库的检索，避免无关内容干扰。</li><li><strong>检索缓存</strong>: 开启后，完全相同的查询文本会直接复用之前的检索结果，节省 Token 和 API 响应时间。适用于同轮多占位符和重试场景。</li><li><strong>上下文窗口</strong>: 取最近 N 轮对话（User + AI），分别向量化后加权融合为检索向量，提供比单条用户消息更丰富的语义上下文。</li></ul><h2 id="_4-调试与分析" tabindex="-1">4. 调试与分析 <a class="header-anchor" href="#_4-调试与分析" aria-label="Permalink to &quot;4. 调试与分析&quot;">​</a></h2><p>如果你觉得 AI “胡言乱语”或没有引用知识库内容：</p><ol><li>打开 <strong><a href="./analyzer">上下文分析器</a></strong>。</li><li>在“结构化视图”中找到 <strong>「知识库结果」</strong> 类型的消息。</li><li>查看检索到的内容、相似度分数以及它在最终 Prompt 中的位置。</li></ol><hr><h3 id="相关阅读" tabindex="-1">相关阅读 <a class="header-anchor" href="#相关阅读" aria-label="Permalink to &quot;相关阅读&quot;">​</a></h3><ul><li><a href="./../../knowledge-base">知识库管理工具指南</a></li><li><a href="./../agents/parameters#3-知识库-rag">Agent 参数配置</a></li><li><a href="./analyzer">上下文分析器</a></li></ul></div>',1)])])}const p=o(r,[["render",n]]);export{u as __pageData,p as default};
